final:
module ring_counter
    (
        input clk,
        input reset,
        output reg [2:0] q
    );

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge reset or posedge dbg_halt) 
    begin
        if (reset)
            q <= 3'b001;
        else
            q <= {q[1:0], q[2]};
    end

endmodule
